  ('bookkeeper-moex-00372', 'bookkeeper', 'bookkeeper-moex-111-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '高雄公司因資金週轉需求，110年11月1日將應收帳款$500,000出售予甲銀行，甲銀行支付85% 的帳款金額給高雄公司，另收取5%的手續費，帳款由甲銀行代收，倘若應收帳款收不回來，則甲 銀行對高雄公司無追索權，試問下列關於高雄公司110年11月1日之會計處理敘述，何者正確？', '["貸：應收帳款$425,000", "貸：應收帳款$500,000", "貸：應付帳款$425,000", "貸：應付帳款$450,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:21+00:00", "source_pdf_sha1": "81d95d1b86d0", "answer_pdf_sha1": "910dfc363ebc", "source_family": "moex-gov-tw", "moex": {"exam_code": "111180", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年專技人員高等考試建築師、31類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00373', 'bookkeeper', 'bookkeeper-moex-111-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '宜蘭公司發行的股份計有普通股30,000股，每股面額$10；非累積完全參加特別股9,000股，每股 面額$20，股利率為8%。宜蘭公司過去二年的股本結構沒有改變，也未發過股利。該公司股東會 決議今年發放現金股利$60,000，請問分配給普通股股東的股利為何？', '["$14,400", "$22,500", "$28,500", "$37,500"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:21+00:00", "source_pdf_sha1": "81d95d1b86d0", "answer_pdf_sha1": "910dfc363ebc", "source_family": "moex-gov-tw", "moex": {"exam_code": "111180", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年專技人員高等考試建築師、31類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00374', 'bookkeeper', 'bookkeeper-moex-111-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '下表是台東公司今年的部分資產負債表資料： 12月31日 1月1日 應收利息 $2,000 $8,000 預收租金 $5,000 $3,000 若今年損益表中的利息收入及租金收入共計$10,000，則今年現金基礎的利息收入及租金收入共計 多少？', '["$2,000", "$6,000", "$14,000", "$18,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:21+00:00", "source_pdf_sha1": "81d95d1b86d0", "answer_pdf_sha1": "910dfc363ebc", "source_family": "moex-gov-tw", "moex": {"exam_code": "111180", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年專技人員高等考試建築師、31類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00375', 'bookkeeper', 'bookkeeper-moex-111-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '綠島公司今年的直接人工成本共計$120,000，加工成本共計$180,000，主要成本共計$210,000。 若今年的製成品成本合計為$300,000，期末在製品成本為$50,000，請問今年的期初在製品成本 為何？', '["$0", "$20,000", "$80,000", "$140,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:21+00:00", "source_pdf_sha1": "81d95d1b86d0", "answer_pdf_sha1": "910dfc363ebc", "source_family": "moex-gov-tw", "moex": {"exam_code": "111180", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年專技人員高等考試建築師、31類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00376', 'bookkeeper', 'bookkeeper-moex-111-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '台中農產公司專門飼養乳牛，牛奶為其主要產品，111年11月共生產200,000公升牛奶，每公升 牛奶之公允價值為$50元，出售成本每公升$5元，採集牛奶之員工薪資為$100,000元，其他支出 為$50,000元，試問台中農產公司採集牛奶200,000公升之分錄，下列何者正確？', '["借：消耗性生物資產$10,000,000", "借：消耗性生物資產$9,000,000", "借：農產品$10,000,000", "借：農產品$9,000,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:21+00:00", "source_pdf_sha1": "81d95d1b86d0", "answer_pdf_sha1": "910dfc363ebc", "source_family": "moex-gov-tw", "moex": {"exam_code": "111180", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年專技人員高等考試建築師、31類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00377', 'bookkeeper', 'bookkeeper-moex-111-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '新竹公司於111年11月1日購置一間廠房，主要以出租為目的，購買價格為$50,000,000，當初委 託房地產仲介公司尋覓此一投資標的，成交支付其仲介佣金$1,000,000，另支付鑑價師之鑑價費 用$100,000，律師服務費$150,000。取得廠房後，仍委託同一房地產仲介公司代為招租，於111年', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:21+00:00", "source_pdf_sha1": "81d95d1b86d0", "answer_pdf_sha1": "910dfc363ebc", "source_family": "moex-gov-tw", "moex": {"exam_code": "111180", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年專技人員高等考試建築師、31類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00378', 'bookkeeper', 'bookkeeper-moex-111-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '月 1 日出租成功，支付其仲介佣金$300,000，試問新竹公司取得該廠房時之會計處理，下列 何者正確？', '["借：不動產、廠房及設備$50,000,000", "借：不動產、廠房及設備$51,000,000", "借：投資性不動產$50,000,000", "借：投資性不動產$51,250,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:21+00:00", "source_pdf_sha1": "81d95d1b86d0", "answer_pdf_sha1": "910dfc363ebc", "source_family": "moex-gov-tw", "moex": {"exam_code": "111180", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年專技人員高等考試建築師、31類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00379', 'bookkeeper', 'bookkeeper-moex-111-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '苗栗公司於 X1 年初以$150,000 購入機器一部，苗栗公司估計機器的耐用年限為 5 年，殘值為 $25,000，採直線法提列折舊。X2 年底該機器有減損跡象，如果立即出售該機器，估計公允價值 減出售成本為$90,000。如果繼續使用該機器，則未來淨現金流入的折現值為$91,000。X3年底苗 栗公司評估減損跡象已不復存在，且機器的公允價值減出售成本為$76,000，未來淨現金流入的折 現值為$75,000。假設機器的殘值與耐用年限之估計不變，則X3年底苗栗公司應認列的減損迴轉 利益為何？', '["$0", "$6,000", "$7,000", "$9,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:21+00:00", "source_pdf_sha1": "81d95d1b86d0", "answer_pdf_sha1": "910dfc363ebc", "source_family": "moex-gov-tw", "moex": {"exam_code": "111180", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年專技人員高等考試建築師、31類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00380', 'bookkeeper', 'bookkeeper-moex-111-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '下列有關於無形資產之論述，何者正確？', '["無形資產中之專利權認列時，應以其市場價值入帳", "版權、客戶名單以及品牌名稱皆是屬於無形資產", "研究發展費用無論是研究階段或是發展階段之支出，皆不可資本化為無形資產", "無形資產之攤銷大多採用直線法，其表達的帳面價值等同市場價值"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:21+00:00", "source_pdf_sha1": "81d95d1b86d0", "answer_pdf_sha1": "910dfc363ebc", "source_family": "moex-gov-tw", "moex": {"exam_code": "111180", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年專技人員高等考試建築師、31類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00381', 'bookkeeper', 'bookkeeper-moex-111-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '花蓮公司自 X1 年開始營業，主要的營業活動是生產及銷售掌上型電子遊戲機，並對於出售的產 品提供3年的保固服務。該公司估計：出售的產品在銷售後第一年被送回維修之費用約為銷貨收 入的2%，在銷售後第二年被送回維修之費用約為銷貨收入的3%，在銷售後第三年被送回維修之 費用約為銷貨收入的5%。前三年遊戲機的銷貨金額及實際保固服務支出資料如下： 年度 銷貨收入 實際保固服務支出 X1 $300,000 $ 5,000 X2 390,000 15,000 X3 420,000 40,000 請問X3年底的保固負債準備餘額為何？', '["$33,600", "$42,000", "$51,000", "$53,100"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:21+00:00", "source_pdf_sha1": "81d95d1b86d0", "answer_pdf_sha1": "910dfc363ebc", "source_family": "moex-gov-tw", "moex": {"exam_code": "111180", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年專技人員高等考試建築師、31類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL)
